// Montar payload final com dados do Claude + metadados
const msg = $input.all()[0].json;
const claudeResp = msg.content?.[0]?.text || '{}';

let metricas = {};
try {
  metricas = JSON.parse(claudeResp);
} catch (e) {
  // Tentar extrair JSON do texto mesmo se vier com markdown
  const jsonMatch = claudeResp.match(/\{[\s\S]+\}/);
  if (jsonMatch) {
    try { metricas = JSON.parse(jsonMatch[0]); } catch(e2) {}
  }
}

// Pegar dados da etapa anterior via $('Extrair Remetente + Mensagem')
const extraido = $('Extrair Remetente + Mensagem').first().json;

const tipo = metricas.tipo || 'reporte-espontaneo';
const pessoa = extraido.pessoa || 'Desconhecido';
const data = extraido.data;
const hora = extraido.hora;

// Título para o Notion
const titulo = `${pessoa} | ${tipo} | ${data} ${hora}`;

return [{
  json: {
    titulo,
    pessoa,
    tipo,
    data,
    hora,
    falou_com: metricas.falou_com ?? null,
    fechamentos: metricas.fechamentos ?? null,
    reativacoes: metricas.reativacoes ?? null,
    leads_gerados: metricas.leads_gerados ?? null,
    ativacoes: metricas.ativacoes ?? null,
    observacao: metricas.observacao || '',
    confianca: metricas.confianca || 'media',
    content_original: extraido.content_original,
    conversation_id: extraido.conversation_id,
    message_id: extraido.message_id
  }
}];

// Log de erro ou item ignorado — sem ação
const item = $input.first().json;
console.log('[SST-GROUP-PARSER] Ignorado:', JSON.stringify(item));
return [{ json: { status: 'ignorado', motivo: item.motivo || 'filtro_conversa' } }];
